import json, pathlib, anthropic

client = anthropic.Anthropic()

tools = [
    {
        "name": "write_file",
        "description": "Write content to a file at the given path.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "content": {"type": "string"},
            },
            "required": ["path", "content"],
        },
    }
]

def write_file(path: str, content: str) -> str:
    pathlib.Path(path).write_text(content)
    return f"Written {len(content)} chars to {path}"

def human_approve(name: str, args: dict) -> bool:
    print(f"\nAgent wants to call: {name}")
    for k, v in args.items():
        preview = str(v)[:120] + ("..." if len(str(v)) > 120 else "")
        print(f"  {k}: {preview}")
    return input("Approve? [y/N]: ").strip().lower() == "y"

messages = [{"role": "user", "content": "Write a hello world Python script to /tmp/hello.py"}]

for _ in range(10):
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=tools,
        messages=messages,
    )
    messages.append({"role": "assistant", "content": resp.content})
    if resp.stop_reason == "end_turn":
        print(next(b.text for b in resp.content if hasattr(b, "text")))
        break
    results = []
    for block in resp.content:
        if block.type == "tool_use":
            if human_approve(block.name, block.input):   # L2 gate
                result = write_file(**block.input)
            else:
                result = "Action rejected by human."
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
    messages.append({"role": "user", "content": results})

